DROP TABLE IF EXISTS `investigador`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `investigador` (
  `id_i` int NOT NULL AUTO_INCREMENT,
  `nombre` varchar(45) NOT NULL,
  `apellido` varchar(45) DEFAULT NULL,
  `institucion` varchar(45) DEFAULT NULL,
  `especializacion` varchar(30) DEFAULT NULL,
  `id_e` int DEFAULT NULL,
  `id_p` int DEFAULT NULL,
  PRIMARY KEY (`id_i`),
  KEY `id_e` (`id_e`),
  KEY `id_p` (`id_p`),
  CONSTRAINT `fk_inv_1` FOREIGN KEY (`id_e`) REFERENCES `especie` (`id_e`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_inv_2` FOREIGN KEY (`id_p`) REFERENCES `planta` (`id_p`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=401 DEFAULT CHARSET=utf8mb3;
/*!40101 SET character_set_client = @saved_cs_client */;

